using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Returns a greeting message for the given name.")]
    public static string Greet(
        [Description("The name of the person to greet")] string name)
    {
        return $"Hello, {name}! Welcome to the MCP server.";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns current application configuration as JSON.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }
}

